+    let values: Vec<f64> = x
+        .values
+        .iter()
+        .map(|&a| if a == 0.0 || a.is_nan() { 1.0 } else { 0.0 })
+        .collect();
+    Ok(UFuncArray {
+        shape: x.shape.clone(),
+        values,
+        dtype: DType::Bool,
+        integer_sidecar: None,
+    })
+}
